int swap;

t_list* curr = lst;

while(lst->next) {

    if(((*cmp)(lst->data, lst->next->data)) == 0) {

        swap = lst->data;

        lst->data = lst->next->data;

        lst->next->data = swap;

        lst = curr;

    } else lst = lst->next;

}

lst = curr;

return lst;
